@page "/catalog"
@rendermode InteractiveServer
@using sv_ea9bf68e35154bf48237e8d478dcfb62.Services
@inject IProductService ProductService
@inject NavigationManager Navigation

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="catalog-error">
        <p>⚠ @errorMessage</p>
        <button class="btn btn-primary" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <!-- Sidebar Filters -->
        <aside class="catalog-sidebar">
            <h3>Filters</h3>

            <div class="filter-section">
                <h4>Category</h4>
                @if (categories is null)
                {
                    <p class="loading-text">Loading categories…</p>
                }
                else
                {
                    @foreach (var category in categories)
                    {
                        <label class="filter-checkbox">
                            <input type="checkbox"
                                   checked="@selectedCategories.Contains(category)"
                                   @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
                            @category
                        </label>
                    }
                }
            </div>

            <div class="filter-section">
                <h4>Price Range</h4>
                <div class="price-inputs">
                    <input type="number" placeholder="Min" step="0.01" min="0"
                           @bind="minPrice" @bind:event="onchange" class="form-control" />
                    <span>–</span>
                    <input type="number" placeholder="Max" step="0.01" min="0"
                           @bind="maxPrice" @bind:event="onchange" class="form-control" />
                </div>
            </div>

            <div class="filter-section">
                <label class="filter-checkbox">
